final:
module top_module(
    A,
    B,
    SEL,
    Y
);// Module ports
    input  A;
    input  B;
    input  SEL;
    output Y;

    // Local signals
    wire MUX_not_SEL;

    // Invert SEL signal
    not not_SEL_inst (
        MUX_not_SEL,
        SEL
    );

    // Multiplexer
    assign Y = (SEL & A) | (MUX_not_SEL & B);

endmodule
